import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a maximum buffer size
        int maxSize = 10;

        // Truncate user input if it exceeds the maximum buffer size
        String safeInput = userInput.substring(0, Math.min(userInput.length(), maxSize));

        // Create a fixed size buffer with the truncated input
        char[] buffer = new char[maxSize];

        // Copy safe user input into the buffer
        safeInput.getChars(0, safeInput.length(), buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
